  "MC_YAWRAUTO_MAX": {"disp":"Max yaw rate in auto mode","desc":"Limit for yaw rate, has effect for large rotations in autonomous mode, to avoid large control output and mixer saturation. A value of significantly over 60 degrees per second can already lead to mixer saturation. A value of 30 degrees / second is recommended to avoid very audible twitches.","units":"deg/s","min":0,"max":120},
  "MC_YAW_FF": {"disp":"Yaw feed forward","desc":"Feed forward weight for manual yaw control. 0 will give slow responce and no overshot, 1 - fast responce and big overshot.","min":0,"max":1},
  "MC_YAW_P": {"disp":"Yaw P gain","desc":"Yaw proportional gain, i.e. desired angular speed in rad/s for error 1 rad.","units":"1/s","min":0,"max":5},
  "MIS_ALTMODE": {"disp":"Altitude setpoint mode","desc":"0: the system will follow a zero order hold altitude setpoint 1: the system will follow a first order hold altitude setpoint values follow the definition in enum mission_altitude_mode","min":0,"max":1},
  "MIS_DIST_1WP": {"disp":"Maximal horizontal distance from home to first waypoint","desc":"Failsafe check to prevent running mission stored from previous flight at a new takeoff location. Set a value of zero or less to disable. The mission will not be started if the current waypoint is more distant than MIS_DIS_1WP from the current position.","min":0,"max":1000},
  "MIS_ONBOARD_EN": {"disp":"Enable persistent onboard mission storage","desc":"When enabled, missions that have been uploaded by the GCS are stored and reloaded after reboot persistently.","min":0,"max":1},
  "MIS_TAKEOFF_ALT": {"disp":"Take-off altitude","desc":"Even if first waypoint has altitude less then MIS_TAKEOFF_ALT above home position, system will climb to MIS_TAKEOFF_ALT on takeoff, then go to waypoint.","units":"meters"},
  "MIS_YAWMODE": {"disp":"Multirotor only. Yaw setpoint mode","desc":"0: Set the yaw heading to the yaw value specified for the destination waypoint. 1: Maintain a yaw heading pointing towards the next waypoint. 2: Maintain a yaw heading that always points to the home location. 3: Maintain a yaw heading that always points away from the home location (ie: back always faces home). The values are defined in the enum mission_altitude_mode","min":0,"max":3},
  "MIS_YAW_ERR": {"disp":"Max yaw error in degree needed for waypoint heading acceptance","min":0,"max":90},
  "MIS_YAW_TMT": {"disp":"Time in seconds we wait on reaching target heading at a waypoint if it is forced","desc":"If set > 0 it will ignore the target heading for normal waypoint acceptance. If the waypoint forces the heading the timeout will matter. For example on VTOL forwards transiton. Mainly useful for VTOLs that have less yaw authority and might not reach target yaw in wind. Disabled by default.","min":-1,"max":20},
  "MKBLCTRL_TEST": {"disp":"Enables testmode (Identify) of MKBLCTRL Driver"},
  "MPC_ACC_HOR_MAX": {"disp":"Maximum horizonal acceleration in velocity controlled modes","units":"m/s/s","min":2,"max":10},
  "MPC_ALTCTL_DY": {"disp":"ALTCTL throttle curve breakpoint height","desc":"Controls the slope of the reduced sensitivity region. This is the height of the ALTCTL throttle curve at center-dz and center+dz.","min":0,"max":0.2},
  "MPC_ALTCTL_DZ": {"disp":"ALTCTL throttle curve breakpoint","desc":"Halfwidth of deadband or reduced sensitivity center portion of curve. This is the halfwidth of the center region of the ALTCTL throttle curve. It extends from center-dz to center+dz.","min":0,"max":0.2},
  "MPC_HOLD_MAX_XY": {"disp":"Maximum horizontal velocity for which position hold is enabled (use 0 to disable check)","units":"m/s","min":0},
