  "MPC_MANTHR_MAX": {"disp":"Maximum manual thrust","desc":"Limit max allowed thrust. Setting a value of one can put the system into actuator saturation as no spread between the motors is possible any more. A value of 0.8 - 0.9 is recommended.","min":0,"max":1},
  "MPC_MANTHR_MIN": {"disp":"Minimum manual thrust","desc":"Minimum vertical thrust. It's recommended to set it > 0 to avoid free fall with zero thrust.","min":0,"max":1},
