  "PE_ACC_PNOISE": {"disp":"Accelerometer process noise","desc":"Generic defaults: 0.25, multicopters: 0.25, ground vehicles: 0.25. Increasing this value makes the filter trust the accelerometer less and other sensors more.","min":0.05,"max":1},
